module counter_4bit(clk, reset, count);

    input clk;
    input reset;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
        begin
            if (reset)
                count <= 0;
            else
                count <= count + 1;
        end

endmodule
